create table games (
    game_id        number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    team_id        number not null enable,
    opponent_name  varchar2(120 byte) not null enable,
    game_date      date not null enable,
    venue_type     varchar2(10 byte) not null enable,
    arena_name     varchar2(120 byte),
    team_score     number(3, 0),
    opponent_score number(3, 0),
    season_label   varchar2(9 byte) not null enable,
    game_status    varchar2(20 byte) default 'SCHEDULED' not null enable
);

alter table games
    add constraint games_pk primary key ( game_id )
        using index enable;

alter table games
    add constraint games_status_ck
        check ( game_status in ( 'SCHEDULED', 'PLAYED', 'POSTPONED', 'CANCELLED' ) ) enable;

alter table games
    add constraint games_venue_ck
        check ( venue_type in ( 'HOME', 'AWAY', 'NEUTRAL' ) ) enable;


